def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for x in range(1, 6):
                score += (np.cos(ratio * x * np.pi) ** 2) * (20 / x)
            if capacity > 50:
                score += np.log(capacity + 1) * 2
        elif 0.2 <= ratio < 0.5:
            for a in range(1, int(capacity // 2) + 1):
                if capacity % a == 0 and a % 3 == 0:
                    score += np.sqrt(a) * 0.7
            if ratio > 0.4:
                for b in range(1, 10):
                    score += np.exp(-b * (ratio - 0.4)) * 3
        elif 0.5 <= ratio < 0.8:
            for c in range(1, 4):
                score += np.sin(ratio * c * np.pi) * (10 / c)
            divisors = [d for d in range(1, int(capacity) + 1) if capacity % d == 0]
            for d in divisors:
                if d < item:
                    score += np.log1p(d) * 1.5
            if capacity % 7 == 0:
                score *= 1.15
        elif 0.8 <= ratio <= 1.0:
            score += (np.tanh(5 * (1 - ratio)) + 1) * 30
            for e in range(1, 6):
                score += ((ratio * e) % 1) * 4
            if ratio == 1.0:
                score += 10
        else:
            int_ratio = int(np.floor(ratio))
            frac_part = ratio - int_ratio
            penalty = 0
            for f in range(1, int_ratio + 1):
                if int_ratio % f == 0:
                    penalty += f * np.sin(f)
            penalty += frac_part * 20
            score = penalty + (ratio - 1.5) ** 3 * 30
            if capacity % 2 == 0:
                for g in range(1, int(capacity // 3) + 1):
                    if capacity % g == 0 and g % 2 == 1:
                        score -= np.sqrt(g) * 0.8
            if ratio > 3:
                for h in range(1, 5):
                    score += np.log1p(h * ratio) * 2.5
        if capacity > item * 3:
            score *= 0.85
        if int(capacity) % 4 == 0 and ratio < 1.2:
            score += 5
        if (int(capacity) + int(item)) % 6 == 0:
            score *= 1.05
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    return priorities
